        public static void Selecao()
        {
            //VARS LOCAL
            bool verificar;
            int userout;
            //
            while (true)
            {
                Console.WriteLine("==========================================\n" +
                                   "Qual calculadora deseja utiizar?\n" +
                                           "[1] Pitagoras\n" +
                                      "[2] Volume da esfera\n" +
                                          "[3] Area do circulo\n" +
                                      "[4] Comprimento do circulo\n" +
                              "==========================================");

                Console.Write("Sua escolha: ");
                verificar = int.TryParse(Console.ReadLine(), out (userout));
                if (verificar) break;
                Console.Clear();
                Console.WriteLine("Erro, op√ß√£o invalida.");
            }
            switch (userout)
            {
                case 1:
                    CalcPitagoras.Principal();
                    break;
                case 2:
                    CalcEsfera.Principal();
                    break;
                case 3:
                    AreaCirc.Principal();
                    break;
                case 4:
                    break;
            }
        }
