        public static void Escolha()
        {
            //VARIAVEL LOCAL
            bool miniverificar = true;
            //
            while (miniverificar)
            {
                Console.WriteLine("Pressione enter para continuar.");
                _ = Console.ReadLine();
                Console.WriteLine("Deseja usar outra calculadora? (S/n)");
                string retornar = Console.ReadLine();
                switch (retornar)
                {
                    case "y" or "Y" or "S" or "s":
                        miniverificar = false;
                        UserInterface.Selecao();
                        break;
                    case "n" or "N":
                        miniverificar = false;
                        UserInterface.Fim();
                        break;
                    default:
                        break;
                }
                Console.Clear();
                Console.WriteLine("Erro, op√ß√£o invalida, use S para sim e N para n√£o.");
            }
        }
    }
    class CalcPitagoras
    {
        public static void Principal()
        {
            //VARS LOCAL
            bool verificar;
            double cat1;
            double cat2;
            double catqua1;
            double catqua2;
            double resultado;
            //
            while (true)
            {
                Console.WriteLine("Por favor, insira o valor do primeiro cateto.");
                verificar = double.TryParse(Console.ReadLine(), out (cat1));
                if (verificar) break;
                Console.Clear();
                Console.WriteLine("Erro, valor invalido.");
            }
            while (true)
            {
                Console.WriteLine("Por favor, insira o valor do segundo cateto.");
                verificar = double.TryParse(Console.ReadLine(), out (cat2));
                if (verificar) break;
                Console.Clear();
                Console.WriteLine("Erro, valor invalido.");
            }
            catqua1 = (cat1 * cat1);
            catqua2 = (cat2 * cat2);
            resultado = Math.Sqrt(catqua1 + catqua2);
            Console.WriteLine($"O resultado da hipotenusa √©: {resultado}");
            UserInterface.Escolha();
        }
    }
    class CalcEsfera
    {
        //RECEBER GLOBAL
        readonly double pi = VariaveisGlobais.Pi;
        //
        //VARS CLASSE
        bool verificar;
        double userout;
        double volume;
        //
        public static void Principal()
        {
            //VARS LOCAL
            bool verificar;
            int userout;
            //
            Console.WriteLine("==========================================\n" +
                                        "O que deseja fazer ?\n" +
                                        "[1] Usar di√Ęmetro\n" +
                                        "[2]  Usar raio\n" +
                                        "[3]   Voltar \n" +
                              "==========================================");
            while (true)
            {
                Console.Write("Sua escolha: ");
                verificar = int.TryParse(Console.ReadLine(), out (userout));
                if (verificar) break;
                Console.Clear();
                Console.WriteLine("Erro, op√ß√£o invalida.");
            }
            verificar = false;
            switch (userout)
            {
                case 1:
                    var instanciadiametro = new CalcEsfera();
                    instanciadiametro.Diametro();
                    break;
                case 2:
                    var instanciaraio = new CalcEsfera();
                    instanciaraio.Raio();
                    break;
                case 3:
                    UserInterface.Selecao();
                    break;
            }
        }
        public void Diametro()
        {
            //VARS LOCAL
            double dira;
            double ra;
            while (true)
            {
                Console.WriteLine("Por favor, insira o valor do diametro em cent√≠metros: ");
                verificar = double.TryParse(Console.ReadLine(), out (userout));
                if (verificar) break;
                Console.Clear();
                Console.WriteLine("Erro, valor invalido.");
            }
            dira = (userout / 2);
            ra = (dira * dira * dira);
            volume = (4*pi*ra)/3;
            Console.WriteLine($"O volume desta esfera √© {volume} m3");
            UserInterface.Escolha();
        }
